"use client";

import React from "react";
import { motion } from "framer-motion";
import { Info, AlertTriangle, CheckCircle, XCircle } from "lucide-react";

export type PrismAlertType = "info" | "success" | "warning" | "error";

export interface PrismAlertProps {
  type?: PrismAlertType;
  title: string;
  message: string;
  onClose?: () => void;
}

export const PrismAlert: React.FC<PrismAlertProps> = ({
  type = "info",
  title,
  message,
  onClose
}) => {
  const styles = {
    info: {
      from: "from-blue-500/20",
      to: "to-cyan-500/10",
      border: "border-blue-500/30",
      icon: <Info className="text-blue-400" />,
      glow: "shadow-[0_0_30px_rgba(59,130,246,0.15)]"
    },
    success: {
      from: "from-emerald-500/20",
      to: "to-teal-500/10",
      border: "border-emerald-500/30",
      icon: <CheckCircle className="text-emerald-400" />,
      glow: "shadow-[0_0_30px_rgba(16,185,129,0.15)]"
    },
    warning: {
      from: "from-amber-500/20",
      to: "to-orange-500/10",
      border: "border-amber-500/30",
      icon: <AlertTriangle className="text-amber-400" />,
      glow: "shadow-[0_0_30px_rgba(245,158,11,0.15)]"
    },
    error: {
      from: "from-rose-500/20",
      to: "to-red-500/10",
      border: "border-rose-500/30",
      icon: <XCircle className="text-rose-400" />,
      glow: "shadow-[0_0_30px_rgba(244,63,94,0.15)]"
    }
  };

  const selected = styles[type];

  return (
    <motion.div
      initial={{ opacity: 0, y: -20, rotateX: 20 }}
