"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

export interface ParachuteDownloadButtonProps {
  onComplete?: () => void;
  duration?: number; // ms for full download simulation
}

export const ParachuteDownloadButton: React.FC<ParachuteDownloadButtonProps> = ({
  onComplete,
  duration = 3000,
}) => {
  const [state, setState] = useState<"idle" | "downloading" | "complete">("idle");
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    if (state !== "downloading") return;

    const interval = 50; // update every 50ms
    const increment = 100 / (duration / interval);

    const timer = setInterval(() => {
      setProgress((prev) => {
        const next = prev + increment;
        if (next >= 100) {
          clearInterval(timer);
          setState("complete");
          if (onComplete) onComplete();
          // Reset after showing success
          setTimeout(() => {
            setState("idle");
            setProgress(0);
          }, 2000);
          return 100;
        }
        return next;
      });
    }, interval);

    return () => clearInterval(timer);
  }, [state, duration, onComplete]);

  const handleClick = () => {
    if (state === "idle") {
      setState("downloading");
      setProgress(0);
    }
  };

  return (
    <div className="flex items-center justify-center">
      <button
        onClick={handleClick}
        disabled={state !== "idle"}
        className="relative flex flex-col items-center justify-center gap-2 w-64 h-48 bg-transparent outline-none border-none cursor-pointer group select-none"
      >
        {/* Parachute Icon Area */}
        <div className="relative w-20 h-28 flex items-center justify-center">
          <AnimatePresence mode="wait">
            {state === "idle" && (
              <motion.div
                key="idle-icon"
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.8 }}
                className="flex flex-col items-center"
              >
                {/* Download Arrow Icon */}
                <svg
                  width="40"
                  height="40"
                  viewBox="0 0 24 24"
                  fill="none"
                  className="text-cyan-400 group-hover:text-cyan-300 transition-colors"
                >
                  <path
                    d="M12 3v12m0 0l-4-4m4 4l4-4"
                    stroke="currentColor"
                    strokeWidth="2.5"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                  <path
                    d="M4 17v2a2 2 0 002 2h12a2 2 0 002-2v-2"
                    stroke="currentColor"
                    strokeWidth="2.5"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                </svg>
              </motion.div>
            )}

            {state === "downloading" && (
              <motion.div
                key="parachute-icon"
                initial={{ y: -60, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ 
                  y: { duration: duration / 1000, ease: "easeInOut" },
                  opacity: { duration: 0.3 }
                }}
                className="flex flex-col items-center"
              >
                {/* Parachute SVG */}
                <svg
                  width="48"
                  height="56"
                  viewBox="0 0 48 56"
                  fill="none"
                  className="text-cyan-400"
                >
                  {/* Canopy (dome) */}
                  <motion.path
                    d="M4 20 C4 8 44 8 44 20"
                    stroke="currentColor"
                    strokeWidth="2.5"
                    strokeLinecap="round"
                    fill="none"
                  />
                  {/* Canopy segments */}
                  <motion.path
                    d="M4 20 C4 28 16 28 16 20"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    fill="none"
                    initial={{ pathLength: 0 }}
                    animate={{ pathLength: 1 }}
                    transition={{ duration: 0.5 }}
                  />
                  <motion.path
                    d="M16 20 C16 28 32 28 32 20"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    fill="none"
                    initial={{ pathLength: 0 }}
                    animate={{ pathLength: 1 }}
                    transition={{ duration: 0.5, delay: 0.1 }}
