          clearInterval(timer);
          setState("complete");
          if (onComplete) onComplete();
          // Reset after showing success
          setTimeout(() => {
            setState("idle");
            setProgress(0);
          }, 2000);
          return 100;
        }
        return next;
      });
    }, interval);

    return () => clearInterval(timer);
