      <div className="p-4 bg-zinc-900/40 border-t border-zinc-900">
        <div className="relative flex items-center">
          <input 
            type="text" 
            value={inputVal}
            onChange={e => setInputVal(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
