export const PhysicalCreditCard: React.FC = () => {
  const [num, setNum] = useState("");
  const [name, setName] = useState("");
  const [exp, setExp] = useState("");
  const [cvc, setCvc] = useState("");
  const [focused, setFocused] = useState<string | null>(null);

  // Format Helpers
  const formatCardNumber = (value: string) => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    const matches = v.match(/\d{4,16}/g);
    const match = matches && matches[0] || '';
    const parts = [];
    for (let i=0, len=match.length; i<len; i+=4) {
      parts.push(match.substring(i, i+4));
    }
    if (parts.length) return parts.join(' ');
    else return value;
  };

  const isFlipped = focused === "cvc";

  return (
    <div className="w-full max-w-xl flex flex-col md:flex-row gap-10 items-center justify-center p-8 bg-zinc-950 border border-zinc-900 rounded-[2.5rem] shadow-2xl">

      {/* 3D Scene Container */}
      <div className="w-80 h-52 perspective-[1000px] shrink-0">
        <motion.div 
          className="relative w-full h-full transform-style-3d cursor-pointer shadow-2xl rounded-2xl"
          animate={{ rotateY: isFlipped ? 180 : 0, scale: focused ? 1.05 : 1 }}
          transition={{ type: "spring", stiffness: 200, damping: 20 }}
          style={{ transformStyle: "preserve-3d" }}
