      whileTap={{ scale: 0.95 }}
    >
       <div className={`${color}`}>
         {icon}
       </div>
       <span className="absolute top-full mt-2 text-[10px] font-bold text-zinc-400 uppercase tracking-wider whitespace-nowrap pointer-events-none selection:bg-none">
         {label}
       </span>
    </motion.div>
  );
};

